text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        {
          "item": "공개 릴리즈 목표 확정",
          "content": "스모크 테스트 통과 시 공개 릴리즈 목표를 금요일 15:00(KST)로 확정."
        },
        {
          "item": "스모크 테스트 실패 처리 기준",
          "content": "packageName mismatch 발생 시 패키지 설정을 우선 점검하고, 계약 자체가 잘못된 경우에만 `smoke-theme-pack.mjs`를 재검토한다."
        }
      ],
      "rejected_proposals": [
        {
          "item": "`smoke-theme-pack.mjs`에서 packageName 불일치 무시",
          "content": "Hara의 제안은 반려됨."
        }
      ],
      "internal_stretch_goals": [
        {
          "item": "수요일 릴리즈 후보",
          "content": "수요일 릴리즈는 내부 Stretch Goal로만 운영되며 확정 일정 아님."
        }
      ]
    },
    "non_decisions": [
      {
        "item": "README install steps 검토 소유자",
        "content": "목요일까지 검토 희망 언급은 있었으나, 담당자 지정은 되지 않음."
      },
      {
        "item": "타르볼 경로 점검 마감시한",
        "content": "Hara의 경로 점검은 Minjun 스모크 결과 공유 후 진행하되, 절대 기한은 미정."
      }
    ],
    "risks": [
      {
        "item": "Tarball 경로 오류",
        "content": "생성된 tarball 경로가 잘못되면 릴리즈 지연 가능성 존재."
      },
      {
        "item": "README 문서 노후",
        "content": "README 설치 단계가 오래되면 릴리즈 노트 및 사용자 안내가 오도될 수 있음."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리즈 승인 권한자",
        "content": "아직 지정되지 않음."
      },
      {
        "item": "릴리즈 노트에 내부 수요일 stretch goal 반영 여부",
        "content": "결정되지 않음."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 금요일 10:00(KST)까지 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 테스트 공유 이후 생성된 tarball 경로 확인",
      "due": "미정(공유 후)",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "미정",
      "task": "README install steps 검토",
      "due": "목요일(가능 시)",
      "status": "미확정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 이전에 Minjun 스모크 결과가 실제 공유되었는지 확인하고, 결과 기준으로 Hara의 tarball 경로 점검을 즉시 진행한다.",
      "스크립트 변경 제안은 packageName mismatch를 직접 무시하지 말고 계약/구성 점검 순서를 지키는지 확인한다.",
      "릴리즈 노트 반영 범위를 최종 승인자 확정 전까지 열어 두고, 수요일 stretch goal는 내부 커뮤니케이션에서만 사용했는지 점검한다."
    ],
    "what_not_to_invent": [
      "고객명, 협력사명, 예산, 보안 사고, 운영 장애, 법무 승인 요건, 확정 소유자, 절대 마감일(날짜/시간)을 추가로 추정해 작성하지 않는다.",
      "최종 릴리즈 승인자와 릴리즈 노트 문구(수요일 stretch goal 반영 여부)는 미결정 항목으로 유지한다."
    ]
  },
  "non_invention_rules": [
    "원문에서 명시되지 않은 고객/예산/보안/아웃티지/법무/마감/담당자/소유권 사실은 추가하지 않는다.",
    "README 검토는 '가능 시' 언급만 있으므로 확정 마감시간으로 환원하지 않는다.",
    "회의록에서 미제공된 금전, 법률, 운영, 계약 조항 등은 추정하지 않는다.",
    "수요일 계획은 stretch goal이므로 공개 릴리즈 확정일로 해석하지 않는다."
  ]
}
